// frontend/src/components/vouchers/MyVouchers.js
import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import api from '../../services/api';
import './Voucher.css';

const MyVouchers = () => {
    const [vouchers, setVouchers] = useState([]);
    const [stats, setStats] = useState({ total: 0, active: 0, total_balance: 0 });
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState('');

    useEffect(() => {
        loadVouchers();
    }, []);

    const loadVouchers = async () => {
        setLoading(true);
        try {
            const response = await api.get('/vouchers/my');
            if (response.data.success) {
                setVouchers(response.data.data.vouchers);
                setStats(response.data.data.stats);
            } else {
                setError('Failed to load vouchers');
            }
        } catch (error) {
            console.error('Error loading vouchers:', error);
            setError('Network error');
        } finally {
            setLoading(false);
        }
    };

    const formatDate = (dateString) => {
        const date = new Date(dateString);
        return date.toLocaleDateString('en-ZA', {
            day: 'numeric',
            month: 'short',
            year: 'numeric'
        });
    };

    const getStatusClass = (status) => {
        switch (status) {
            case 'active': return 'status-active';
            case 'expired': return 'status-expired';
            case 'used': return 'status-used';
            default: return '';
        }
    };

    if (loading) {
        return <div className="loading-spinner">Loading your vouchers...</div>;
    }

    return (
        <div className="my-vouchers-container">
            <div className="vouchers-header">
                <h1>My Vouchers</h1>
                <Link to="/vouchers/buy" className="btn-buy">
                    + Buy New Voucher
                </Link>
            </div>

            {error && <div className="voucher-error">{error}</div>}

            {/* Stats Cards */}
            <div className="voucher-stats">
                <div className="stat-card">
                    <span className="stat-value">{stats.total}</span>
                    <span className="stat-label">Total Vouchers</span>
                </div>
                <div className="stat-card">
                    <span className="stat-value">{stats.active}</span>
                    <span className="stat-label">Active</span>
                </div>
                <div className="stat-card">
                    <span className="stat-value">R {stats.total_balance}</span>
                    <span className="stat-label">Total Balance</span>
                </div>
            </div>

            {/* Balance Checker */}
            <div className="balance-checker">
                <h3>Check Voucher Balance</h3>
                <p>Dial <code>*130*469#</code> from any phone to check balance via USSD</p>
            </div>

            {/* Vouchers List */}
            {vouchers.length === 0 ? (
                <div className="no-vouchers">
                    <p>You don't have any vouchers yet.</p>
                    <Link to="/vouchers/buy" className="btn-primary">
                        Buy Your First Voucher
                    </Link>
                </div>
            ) : (
                <div className="vouchers-grid">
                    {vouchers.map(voucher => (
                        <div key={voucher.id} className="voucher-item">
                            <div className={`voucher-status ${getStatusClass(voucher.current_status)}`}>
                                {voucher.current_status}
                            </div>

                            <div className="voucher-code">
                                <strong>{voucher.voucher_code}</strong>
                                {voucher.pin_code && (
                                    <span className="voucher-pin">PIN: {voucher.pin_code}</span>
                                )}
                            </div>

                            <div className="voucher-balance">
                                <div className="balance-row">
                                    <span>Face Value:</span>
                                    <span>R {voucher.face_value}</span>
                                </div>
                                <div className="balance-row highlight">
                                    <span>Current Balance:</span>
                                    <span>R {voucher.current_balance}</span>
                                </div>
                            </div>

                            <div className="voucher-dates">
                                <div className="date-row">
                                    <span>Expires:</span>
                                    <span className={voucher.current_status === 'expired' ? 'expired' : ''}>
                                        {formatDate(voucher.expires_at)}
                                    </span>
                                </div>
                            </div>

                            {voucher.template_name && (
                                <div className="voucher-template">
                                    {voucher.template_name}
                                </div>
                            )}

                            {voucher.current_status === 'active' && (
                                <button className="btn-use">Use Voucher</button>
                            )}
                        </div>
                    ))}
                </div>
            )}

            {/* Instructions */}
            <div className="voucher-instructions">
                <h4>How to Use Vouchers</h4>
                <ol>
                    <li>Select a job and choose "Pay with Voucher"</li>
                    <li>Enter your voucher code and PIN</li>
                    <li>The amount will be deducted from your balance</li>
                    <li>Worker receives payment confirmation</li>
                    <li>You can check balance anytime via USSD</li>
                </ol>
            </div>
        </div>
    );
};

export default MyVouchers;
